"""
title: Google Stitch Designer
author: WidgeTDC Platform
version: 1.0.0
description: Access Google Stitch AI designs â€” list projects, view screens, get generated HTML/CSS code
"""
import requests
import json
import subprocess
from datetime import datetime, timezone
from pydantic import BaseModel, Field


class Tools:
    class Valves(BaseModel):
        stitch_access_token: str = Field(
            default="",
            description="Google OAuth access token for Stitch API. Get via: gcloud auth print-access-token"
        )
        stitch_api_key: str = Field(
            default="",
            description="Alternative: Google API key for Stitch (if no OAuth token)"
        )
        google_cloud_project: str = Field(
            default="",
            description="Google Cloud project ID (optional, for billing attribution)"
        )

    def __init__(self):
        self.valves = self.Valves()
        self.base_url = "https://stitch.googleapis.com/mcp"
        self._request_id = 0

    def _headers(self) -> dict:
        h = {"Content-Type": "application/json", "Accept": "application/json, text/event-stream"}
        if self.valves.stitch_api_key:
            h["X-Goog-Api-Key"] = self.valves.stitch_api_key
        elif self.valves.stitch_access_token:
            h["Authorization"] = f"Bearer {self.valves.stitch_access_token}"
        if self.valves.google_cloud_project:
            h["X-Goog-User-Project"] = self.valves.google_cloud_project
        return h

    def _rpc(self, method: str, params: dict = None) -> dict:
        self._request_id += 1
        body = {"jsonrpc": "2.0", "id": self._request_id, "method": method}
        if params:
            body["params"] = params
        r = requests.post(self.base_url, headers=self._headers(), json=body, timeout=60)
        data = r.json()
        if "error" in data:
            raise Exception(f"RPC error {data['error'].get('code')}: {data['error'].get('message')}")
        return data.get("result", {})

    def _call_tool(self, tool_name: str, arguments: dict = None) -> dict:
        params = {"name": tool_name}
        if arguments:
            params["arguments"] = arguments
        return self._rpc("tools/call", params)

    def list_stitch_projects(self) -> str:
        """
        List all Google Stitch design projects in your account.
        :return: List of Stitch projects with IDs and names
        """
        try:
            result = self._call_tool("list_projects")
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            content = result.get("content", [])
            if isinstance(content, list) and content:
                text = content[0].get("text", json.dumps(content, indent=2))
            else:
                text = json.dumps(result, indent=2)
            return f"### Stitch Projects\n\n{text}\n\n---\n**Source:** Google Stitch | {ts}"
        except Exception as e:
            return f"Error listing projects: {e}"

    def list_stitch_screens(self, project_id: str) -> str:
        """
        List all screens/pages in a Stitch design project.
        :param project_id: Stitch project ID (from list_stitch_projects or project URL)
        :return: List of screens with IDs, names, and preview info
        """
        try:
            result = self._call_tool("list_screens", {"projectId": project_id})
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            content = result.get("content", [])
            if isinstance(content, list) and content:
                text = content[0].get("text", json.dumps(content, indent=2))
            else:
                text = json.dumps(result, indent=2)
            return f"### Screens in Project {project_id}\n\n{text}\n\n---\n**Source:** Google Stitch | {ts}"
        except Exception as e:
            return f"Error listing screens: {e}"

    def get_screen_code(self, project_id: str, screen_id: str) -> str:
        """
        Get the generated HTML/CSS code for a specific Stitch screen design.
        Use this to retrieve production-ready frontend code from AI-generated designs.
        :param project_id: Stitch project ID
        :param screen_id: Screen/node ID (from list_stitch_screens or the node-id URL param)
        :return: HTML/CSS code for the screen
        """
        try:
            result = self._call_tool("get_screen_code", {"projectId": project_id, "screenId": screen_id})
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            content = result.get("content", [])
            if isinstance(content, list) and content:
                text = content[0].get("text", json.dumps(content, indent=2))
            else:
                text = json.dumps(result, indent=2)
            return f"### Screen Code ({screen_id})\n\n```html\n{text[:8000]}\n```\n\n---\n**Source:** Google Stitch | {ts}"
        except Exception as e:
            return f"Error getting screen code: {e}"

    def get_screen_image(self, project_id: str, screen_id: str) -> str:
        """
        Get a screenshot/preview image of a Stitch screen as base64.
        :param project_id: Stitch project ID
        :param screen_id: Screen/node ID
        :return: Base64-encoded screenshot image
        """
        try:
            result = self._call_tool("get_screen_image", {"projectId": project_id, "screenId": screen_id})
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            content = result.get("content", [])
            if isinstance(content, list) and content:
                item = content[0]
                if item.get("type") == "image":
                    b64 = item.get("data", "")
                    mime = item.get("mimeType", "image/png")
                    return f"### Screen Preview ({screen_id})\n\n![Screen](data:{mime};base64,{b64[:100]}...)\n\nBase64 image returned ({len(b64)} chars).\n\n---\n**Source:** Google Stitch | {ts}"
                text = item.get("text", json.dumps(item, indent=2))
            else:
                text = json.dumps(result, indent=2)
            return f"### Screen Image ({screen_id})\n\n{text[:2000]}\n\n---\n**Source:** Google Stitch | {ts}"
        except Exception as e:
            return f"Error getting screen image: {e}"

    def build_site_from_stitch(self, project_id: str, routes_json: str = "") -> str:
        """
        Build a deployable site from a Stitch project by mapping screens to URL routes.
        If routes_json is empty, builds with default routing (each screen = one page).
        :param project_id: Stitch project ID
        :param routes_json: Optional JSON array of route mappings, e.g. [{\"screenId\": \"abc\", \"route\": \"/\"}]
        :return: Site build result with HTML for each page
        """
        try:
            args = {"projectId": project_id}
            if routes_json:
                args["routes"] = json.loads(routes_json)
            result = self._call_tool("build_site", args)
            ts = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
            content = result.get("content", [])
            if isinstance(content, list) and content:
                text = content[0].get("text", json.dumps(content, indent=2))
            else:
                text = json.dumps(result, indent=2)
            return f"### Built Site from Project {project_id}\n\n{text[:10000]}\n\n---\n**Source:** Google Stitch build_site | {ts}"
        except Exception as e:
            return f"Error building site: {e}"
